var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"어제 아침, 예정에 없던 일식 현상과 함께 짧은 시간 천둥번개를 동반한 국지성호우가 쏟아졌습니다.","JPN":"昨朝、突発的な日食現象とともに、\\n短時間で雷を伴った集中豪雨が発生しました。","ENG":"Yesterday morning, multiple weather anomalies occurred, including an unexpected eclipse and torrential rainfall with thunder and lightning.","TWN":"昨天早上，突然出現日蝕現象，並且短時間內降下局部性豪雨。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"환경당국은 이번 이상현상이 자연적으로는 발생할 수 없는 이례적인 재난이라며, 도시관리국의 침식재난부서에 원인 조사를 맡기기로……","JPN":"環境局は今回の異常現象について、\\n自然発生はあり得ない異例の災害と認定し、\\n都市管理局の侵食災害部署に原因調査を任せることに……","ENG":"City Management has declared a state of disaster, reporting that this doesn’t appear to be a natural occurrence, and they requested an investigation by the Corruption Disaster Department...","TWN":"環境當局稱此次異常現象，並非自然發生的罕見災難，決定委託城市管理局的侵蝕災難部門，進行相關調查……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에, 괜찮으신가요?","JPN":"早苗様、大丈夫ですか？","ENG":"Sanae, are you alright?","TWN":"早苗，你還好嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예, 어머니의 장례를 치러드리고 나니 한결 홀가분하군요.","JPN":"はい。母の葬儀が終わり、気持ちを整理できました。","ENG":"Yes, I feel much better after giving my mother a proper funeral.","TWN":"我沒事，辦完家母的葬禮後，覺得整個人輕鬆許多。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대의 가문이 이런 불미스러운 일을 겪게 된 것은 유감입니다.","JPN":"貴方の家門がこのような不祥事に見舞われたことを、とても心苦しく思います。","ENG":"I am sorry that your family had to go through such tragedy.","TWN":"我很抱歉，你的家族曾經歷過這樣不光彩的事情。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"공석이 아닌 개인적인 자리에서 다시 한번 사과를 드리고 싶었어요.","JPN":"公の立場ではなく個人の立場から、もう一度お詫びさせてください。","ENG":"I wanted to apologize once again personally.","TWN":"我在非公開的私人場合上再次向你道歉。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머니는…… 당주님의 도움 덕에 당신의 본분을 다할 수 있었습니다.","JPN":"母は……ご当主様のご助力のおかげで念願を果たすことができました。","ENG":"My mother... She fulfilled her duty thanks to you.","TWN":"家母……因為有堂主的幫助才能盡到本份。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"오히려 당주님께는 제가 감사를 드려야 할 일이지요.","JPN":"むしろご当主様には私が感謝しなければなりません。","ENG":"I am the one who should be thanking you.","TWN":"反而是我要感謝堂主才對。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"고마워요. 그렇게 말해줘서.","JPN":"そうおっしゃってくださって、ありがとうございます。","ENG":"Thank you for your kind words.","TWN":"謝謝你這麼說。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이제, 앞으로 어떻게 할 계획이신가요?","JPN":"それで、これからはどうする予定ですか？","ENG":"So, what’s your plan?","TWN":"之後有什麼打算呢？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"계획이라고 하심은?","JPN":"予定ということは？","ENG":"My plan?","TWN":"什麼打算？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하야미 가문이 맡아왔던 본연의 역할은 호위 무사입니다.","JPN":"速水家が果たしてきた本来の役割は護衛です。","ENG":"The Hayami family is traditionally a bodyguard family.","TWN":"速水家族原本就是護衛武士。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다시 그때처럼 돌아갈 수도 있을 거예요.","JPN":"また本来の役割に戻ることもできるでしょう。","ENG":"You may come back.","TWN":"或許能再會回復原樣，"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"물론. 그대가 원한다면 말이죠.","JPN":"もちろん、あなたが望むならです。","ENG":"If you wish.","TWN":"當然，前提是你願意。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님을 곁에서 모실 수 있다면 저에겐 거절할 이유가 없습니다.","JPN":"ご当主様をそばでお守りすることができるのでしたら、\\n私には断る理由がございません。","ENG":"I will gladly serve you, if I can.","TWN":"如果能陪在堂主身邊，我沒有理由拒絕。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"다만, 당주님의 곁을 지켜주는 분은 따로 있으니까요.","JPN":"ですが、ご当主様をそばで守ってくださる方は既にいらっしゃいますから。","ENG":"But you already have a bodyguard.","TWN":"但是，堂主身邊現在另有其人。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"호위 무사의 이름이 둘일 필요는 없습니다.","JPN":"護衛の名が二つもある必要はありません。","ENG":"You don’t need two.","TWN":"護衛武士不需要有兩位。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런…… 가요.","JPN":"そう……ですか。","ENG":"I see...","TWN":"是……嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만 제가 연합을 떠날 것을 걱정하신다면, 그런 염려는 않으셔도 됩니다.","JPN":"ですが、私が連合を去ることを懸念していらっしゃるのでしたら、\\nそのような心配は必要ありません。","ENG":"However, if you’re worried that I might leave the Alliance, don’t be.","TWN":"如果您是擔心我離開聯盟，那您大可放心。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"연합의 집안일을 거들고 시중을 드는 생활 외엔 달리 생각해본 앞날이 없으니까요.","JPN":"連合の家事を手伝い、仕えること以外に考えている未来はございません。","ENG":"I want nothing else besides serving the Alliance and helping with your housework.","TWN":"因爲我對於未來的打算，就只有幫助聯盟的家務和侍奉。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"오로치 또한…… 언제 다시 깨어날지 모르는 일이죠.","JPN":"オロチも……いつまた目覚めるかわかりませんので。","ENG":"And... who knows when Orochi will come back?","TWN":"而且大蛇…也不知道什麼時候會再醒過來。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그러니, 앞으로도 잘 부탁드립니다.","JPN":"ですので、これからも何卒よろしくお願い申し上げます。","ENG":"I look forward to continuing serving you, Lady Nanahara.","TWN":"所以，之後還請多多指教。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저도 잘 부탁드려요.","JPN":"こちらこそ、よろしくお願いいたします。","ENG":"Thank you.","TWN":"我也請你多多指教。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하아……","JPN":"はあ……","ENG":"*Sigh*","TWN":"哀哀……"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐야, 미나토. 아침부터 한숨이나 쉬고.","JPN":"何だよ、湊。朝からそんなため息ついて。","ENG":"What is it, Minato? What’s with the sigh?","TWN":"南裕夏，你幹嘛一大早就開始嘆氣！"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"지금 내 수중에 돈이 한 푼도 없다는 현실이 떠올라버렸어.","JPN":"今の自分が無一文っていう現実に気づいちゃったんだよ。","ENG":"I just realized that I don’t have a single penny in my pocket.","TWN":"突然想起我口袋裡一毛錢也沒有的殘酷現實。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아키…… 정말로 내 통장을 탈탈 털어가 버릴 줄이야.","JPN":"秋……まさか本当に僕の全財産をごっそり持っていくなんて。","ENG":"Aki... really took everything from me.","TWN":"廣瀨秋……竟然真的把我存摺裡的錢全部挖光。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"후후, 너무 걱정이 많군. 재물이란 있다가도 없는 법.","JPN":"フフフ、心配性だな。財産とはあってもすぐに無くなるものだ。","ENG":"Hah hah, don’t worry. Money is something that comes and goes.","TWN":"呵呵，沒什麼好煩惱的，錢就是這樣來來去去的。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그 반대의 경우도 마찬가지지.","JPN":"その逆の場合も同じだ。","ENG":"There’s nothing to worry about.","TWN":"反過來也是一樣。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"침식체 토벌 건 하나만 잡히면 우린 돈방석에 앉을 수 있을 거다, 미나토.","JPN":"侵食体討伐の依頼を1件でもこなせれば、\\nオレたちだって金持ちになれるんだぜ、湊。","ENG":"We’ll make a lot of money when we take a C.O. subjugation job.","TWN":"只要接到一個侵蝕體討伐案件，我們就能賺大錢啦，南裕夏。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"네가 가진 최강비기, <color=#ffd34c>아홉 개의 태양</color>이라면 침식체 선조님이 와도 한 방에 나가떨어질 테니까.","JPN":"お前が持つ最強の秘技、<color=#ffd34c>九つの太陽</color>があれば侵食体のご先祖様が来ようが一発で吹っ飛ばせるからな。","ENG":"Your ultimate skill, <color=#ffd34c>Nine Suns</color>, will shoot down any C.O.s we meet.","TWN":"你有的最強絕招 <color=#ffd34c>九重天陽</color>，就算侵蝕體的祖宗八代都跑來，你也可以一網打盡的。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 그거 말이지.","JPN":"あ、それなんだけど。","ENG":"Oh, that.","TWN":"呃，那個嘛。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"혹시나 하는 마음으로 공터에 나가서 기합 잡고서 다시 해봤지만, 흉내조차 못 내겠더라.","JPN":"気になったから、この前空地で気合いを入れてもう一度やってみたんだけど、全然できなかったよ。","ENG":"I don’t think I can do it again. I tried my best to use the skill, but the result was not even close.","TWN":"抱著試試看心態，到空地上想說再試一次，但是完全弄不出來。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"분명 그땐 화살 하나로 거대한 침식체도 잡았었는데, 이제 와선 그것마저 안되고 말이지.","JPN":"あの時は確かに矢の一本で巨大な侵食体も倒せたのに、\\n今はそれもできないし。","ENG":"I did kill a huge C.O. with a single arrow, but I can’t even do that now.","TWN":"當時明明用一支箭就解決巨大侵蝕體，結果現在連這個也無法。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭣?! 그게 사실이냐?","JPN":"えっ！？　マジかよ！","ENG":"What?! Are you for real?","TWN":"什麼？！是真的嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"크윽, 그때 사진으로 남겨뒀어야 했는데. 불찰이군.","JPN":"くそっ、あの時写真でも撮っとくべきだったか。不覚を取ったぜ。","ENG":"Gah, I should have taken your picture when you did that. What a shame.","TWN":"咳咳，當時候應該拍照的，是我的錯。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아직도 꿈만 같아.","JPN":"まだ夢みたいだ。","ENG":"It all feels like a dream.","TWN":"到現在還很沒有真實感。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그날 있었던 일들이 전부 사실이라니.","JPN":"あの日のことが、全部現実だなんて。","ENG":"I can’t believe all these things actually happened.","TWN":"那天發生的事竟然是真實的。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나도 마찬가지다.","JPN":"オレも同じだ。","ENG":"Same here.","TWN":"我也是一樣。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……사나에 씨는 잘 있겠지?","JPN":"……早苗さんは元気にしてるかな。","ENG":"... I wonder how Sanae is doing.","TWN":"……早苗還好吧？"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"궁금하면 학교 끝나는 대로 가볼까?","JPN":"気になるなら学校が終わった後行ってみる？","ENG":"Maybe we can visit her after school.","TWN":"想知道的話，放學後去看看吧？"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"바, 바보야. 그냥 해본 소리야.","JPN":"バ、バカ言うなよ。ただ言ってみただけだ。","ENG":"Y-you fool, I didn’t really mean to...","TWN":"傻…傻瓜，我隨口問問而已。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐야, 그 허둥대는 반응은?","JPN":"なんだよ、その慌てるような反応は？","ENG":"Why are you flustered?","TWN":"幹嘛，這慌張的反應是？"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"미나토! 좋은 아침!","JPN":"湊！　おはよう！","ENG":"Minato! Good morning!","TWN":"南裕夏，早安！"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"좋은 아침, 이로하.","JPN":"おはよう、いろは。","ENG":"Good morning, Iroha.","TWN":"早安，伊呂波。"},"stage":{"bg":"CLASS","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"오는 길에 벚꽃 봤어? 도시관리국에서 올해 엄청 심었다는 얘긴 들었는데, 그게 이번에 필 줄은 몰랐네.","JPN":"通学路の桜は見た？　都市管理局で今年たくさん植えたって話は\\n聞いてたけど、それがこんなすぐに咲くとは思わなかったわ。","ENG":"Did you see the cherry blossoms outside? I heard City Management planted lots of those trees, but didn’t know they were going to bloom now.","TWN":"來的路上有看到櫻花嗎？ 聽說城市管理局今年有種很多，沒想到這次會開花。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응? 벚꽃이 있었던가? 제대로 못 봤어.","JPN":"うん？　桜なんてあったっけ？　ちゃんと見てないや。","ENG":"Oh, really? I didn’t notice.","TWN":"嗯？有櫻花嗎？我沒看清楚。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"하여간, 낭만이 없다니까.","JPN":"まったく、風情もなにもないんだから。","ENG":"You’re so insensitive.","TWN":"真是的，一點都不浪漫。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그럼 있다가 다 같이 벚꽃 놀이나 갈래?","JPN":"じゃあ、後でみんなで花見でも行かない？","ENG":"Shall we go and see the flowers later today?","TWN":"那待會要一起去賞櫻嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥, 시시한 꽃구경 따위로 이 몸을 귀찮게 하지 마라, 소녀.","JPN":"ふん、つまらない花見なんかでオレ様を煩わすな、少女よ。","ENG":"Hmpf, don’t bother me with petty flowers, girl.","TWN":"哼，這位少女，賞花我沒興趣。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"아, 그래? 건너편 여고 애들도 같이 가기로 했는데, 그래도 안 올 거야?","JPN":"あ、そう？　うちの学校の向かいにある女子高の子たちも一緒に行くけど、\\nそれでも来ない？","ENG":"Oh, really? I called my friends from the girl’s high school right across the street. Are you sure you’re not coming?","TWN":"喔，是喔？我和對面女中的學生約好要一起去，你確定不來嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥, 날 뭐라고 생각하는 거냐?","JPN":"ふん、オレ様を何だと思っている？","ENG":"Hah, who do you think I am?","TWN":"哼，你把我當什麼人啦？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"으악! 아, 알겠어. 가면 될 거 아냐!","JPN":"いてっ！　わ、わかった。行けばいいんだろ！","ENG":"Argh! Okay, okay, I’ll come!","TWN":"哎唷！好啦，去就去！"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"살짝 꼬집은 걸로 엄살은.","JPN":"ちょっとつねった程度で大げさね。","ENG":"It was just a little pinch, you didn’t have to scream.","TWN":"我才輕輕捏一下而已，裝什麼裝！"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"넌 뺨을 비트는 게 꼬집는 거냐?","JPN":"頬を捻るのはつねるとは言わないぞ！","ENG":"You almost tried to tear off my cheek, do you call that a little pinch?","TWN":"你那哪叫輕輕的？"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하……","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"때론 아주 사소한 계기가, 오래 전의 기억을 떠올리게 하고는 한다.","JPN":"時に、とても些細なきっかけが昔の記憶を呼び起こすことがある。","ENG":"Sometimes, trivial things bring up old memories.","TWN":"有時非常小的事情，會讓人想起很久以前的事。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그날도, 이렇게 거리에 벚꽃이 만발해있었다.","JPN":"あの日も、今日みたいに街に桜が咲き乱れていた。","ENG":"On that day, the street was filled with cherry blossoms just like today.","TWN":"那天也是，街上櫻花盛開。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"우리는 다른 길을 걷다가, 그곳에서 우연히 만났다.","JPN":"僕たちは別々の道を歩んでいて、そこで偶然出会った。","ENG":"We were just going our own ways, and ran into each other unexpectedly.","TWN":"我們原本走在不同的路上，後來在那裡偶然相遇。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그것이 인연이라는 걸 알아챘을 땐.","JPN":"そして、それが縁だと気づいた時は。","ENG":"And when I realized that it was meant to be...","TWN":"而且，當你發現那是緣分時，"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"서로가 걷던 길도, 어느덧 교차점을 지나고 있었다.","JPN":"互いが歩んでいた道も、いつしか交差点となっていた。","ENG":"We were already passing through the crossing point.","TWN":"彼此走過的路，也不知不覺來到交叉點。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"정말이지.","JPN":"本当に。","ENG":"I would say...","TWN":"真的是，"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"지극히 평범한 일이다.","JPN":"ごく普通のことだ。","ENG":"It was very ordinary.","TWN":"這是一件非常平凡的事情。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};